import React from 'react';
import { Link } from 'react-router-dom';
import { FaCamera, FaUserCircle } from 'react-icons/fa';

const Navbar = () => {
  return (
    <nav className="bg-gray-900 text-white p-4 shadow-md">
      <div className="container mx-auto flex justify-between items-center">
        {/* Logo */}
        <Link to="/" className="text-xl font-bold flex items-center space-x-2 hover:text-gray-300 transition">
          <FaCamera />
          <span>JBS Studios</span>
        </Link>

        {/* Navigation Links */}
        <div className="hidden md:flex space-x-6">
          <Link to="/gallery" className="nav-link">
            Gallery
          </Link>
          <Link to="/booking" className="nav-link">
            Book a Session
          </Link>
        </div>

        {/* Login Button */}
        <Link to="/login" className="flex items-center bg-blue-600 px-4 py-2 rounded-lg hover:bg-blue-700 transition">
          <FaUserCircle className="mr-2" />
          <span>Login</span>
        </Link>
      </div>
    </nav>
  );
};

export default Navbar;
